SELECT *
FROM products
WHERE status = 'APPROVED'
  AND (
        category_id = #{category_id}
        OR category_id IN (
            SELECT category_id
            FROM categories
            WHERE parent_id = #{category_id}
        )
  )
ORDER BY product_id DESC
LIMIT #{start}, #{blockList}

SELECT COUNT(*)
FROM products
WHERE status = 'APPROVED'
  AND (
        category_id = #{category_id}
        OR category_id IN (
            SELECT category_id
            FROM categories
            WHERE parent_id = #{category_id}
        )
  )
